/**** 
* Calculate TOTAL and AVERAGE values from CQP_SUMMARY_CLAIMS
* This function loops through all claim rows and computes the sum and average
* for storage, transit, and combined claim values.
* The result is returned as an array containing one object with totals and averages.
*
* @param none
* @return (Array) resultArray containing totals and averages for each claim field
*
* by Adriana Centellas
****/

// Initialize totals
let CQP_FREQUENCY_STORAGE_TOTAL = 0;
let CQP_TOTAL_CLAIMS_STORAGE_TOTAL = 0;
let CQP_FREQUENCY_TRANSIT_TOTAL = 0;
let CQP_TOTAL_CLAIMS_TRANSIT_TOTAL = 0;
let CQP_TOTAL_CLAIMS_COMBINED_TOTAL = 0;

// Initialize averages
let CQP_FREQUENCY_STORAGE_AVERAGE = 0;
let CQP_TOTAL_CLAIMS_STORAGE_AVERAGE = 0;
let CQP_FREQUENCY_TRANSIT_AVERAGE = 0;
let CQP_TOTAL_CLAIMS_TRANSIT_AVERAGE = 0;
let CQP_TOTAL_CLAIMS_COMBINED_AVERAGE = 0;

// Access summary claims array (fallback to empty array)
let summaryClaims = this.CQP_SUMMARY_CLAIMS || [];

// Declare result
let result = [];

// Initialize counter
let count = 0;

summaryClaims.forEach((claim) => {
  // Force values to numbers (NaN becomes 0 with || 0)
  const freqStorage   = Number(claim.CQP_FREQUENCY_STORAGE)        || 0;
  const totalStorage  = Number(claim.CQP_TOTAL_CLAIMS_STORAGE)     || 0;
  const freqTransit   = Number(claim.CQP_FREQUENCY_TRANSIT)        || 0;
  const totalTransit  = Number(claim.CQP_TOTAL_CLAIMS_TRANSIT)     || 0;
  const totalCombined = Number(claim.CQP_TOTAL_CLAIMS_COMBINED)    || 0;

  // Accumulate totals
  CQP_FREQUENCY_STORAGE_TOTAL      += freqStorage;
  CQP_TOTAL_CLAIMS_STORAGE_TOTAL   += totalStorage;
  CQP_FREQUENCY_TRANSIT_TOTAL      += freqTransit;
  CQP_TOTAL_CLAIMS_TRANSIT_TOTAL   += totalTransit;
  CQP_TOTAL_CLAIMS_COMBINED_TOTAL  += totalCombined;

  count++;
});

// Avoid division by zero
if (count === 0) {
  count = 1;
}

// Calculate averages
CQP_FREQUENCY_STORAGE_AVERAGE      = Math.round(CQP_FREQUENCY_STORAGE_TOTAL / count);
CQP_TOTAL_CLAIMS_STORAGE_AVERAGE   = CQP_TOTAL_CLAIMS_STORAGE_TOTAL / count;
CQP_FREQUENCY_TRANSIT_AVERAGE      = Math.round(CQP_FREQUENCY_TRANSIT_TOTAL / count);
CQP_TOTAL_CLAIMS_TRANSIT_AVERAGE   = CQP_TOTAL_CLAIMS_TRANSIT_TOTAL / count;
CQP_TOTAL_CLAIMS_COMBINED_AVERAGE  = CQP_TOTAL_CLAIMS_COMBINED_TOTAL / count;


// Build result object
result = [{
  CQP_FREQUENCY_STORAGE_TOTAL,
  CQP_TOTAL_CLAIMS_STORAGE_TOTAL,
  CQP_FREQUENCY_TRANSIT_TOTAL,
  CQP_TOTAL_CLAIMS_TRANSIT_TOTAL,
  CQP_TOTAL_CLAIMS_COMBINED_TOTAL,
  CQP_FREQUENCY_STORAGE_AVERAGE,
  CQP_TOTAL_CLAIMS_STORAGE_AVERAGE,
  CQP_FREQUENCY_TRANSIT_AVERAGE,
  CQP_TOTAL_CLAIMS_TRANSIT_AVERAGE,
  CQP_TOTAL_CLAIMS_COMBINED_AVERAGE
}];

// Return as array
return result;

/**** 
 * Inline validation for CQP_FREQUENCY_STORAGE and CQP_FREQUENCY_TRANSIT values
 * Checks that each element in CQP_SUMMARY_CLAIMS contains only integer numbers (no negatives)
 * Returns an object with isValid (Boolean) and message (String)
 *
 * @param none
 * @return (Object) { isValid: Boolean, message: String }
 *
 * by Adriana Centellas
 ****/

// Regular expression to validate integers (only positive numbers)
const integerRegex = /^\d+$/;

// Default validation result
let validationResult = { isValid: true, message: "" };

let summaryClaims = this.CQP_SUMMARY_CLAIMS;

// Iterate through array to check each value
for (let i = 0; i < summaryClaims.length; i++) {
  const valueStorage = summaryClaims[i].CQP_FREQUENCY_STORAGE;
  const valueTransit = summaryClaims[i].CQP_FREQUENCY_TRANSIT;

  // Validate FREQUENCY STORAGE
  if (!integerRegex.test(String(valueStorage))) {
    validationResult = {
      isValid: false,
      message: `Error: FREQUENCY STORAGE at row ${i + 1} is not a valid integer. Value received: '${valueStorage}'`
    };
    break; // Stop checking after the first invalid value
  }

  // Validate FREQUENCY TRANSIT
  if (!integerRegex.test(String(valueTransit))) {
    validationResult = {
      isValid: false,
      message: `Error: FREQUENCY TRANSIT at row ${i + 1} is not a valid integer. Value received: '${valueTransit}'`
    };
    break; // Stop checking after the first invalid value
  }
}

// Return final result
return validationResult;
